// ============================================
// IRIS' MATCHA BAR — site logic
// ============================================

// ---- CONFIG ----
// Change this to whatever password you want guests to use.
const SITE_PASSWORD = "opensesame";

// ---- PASSWORD GATE ----
const gate = document.getElementById("gate");
const gateCard = gate.querySelector(".gate-card");
const gateForm = document.getElementById("gateForm");
const passwordInput = document.getElementById("passwordInput");
const gateError = document.getElementById("gateError");
const site = document.getElementById("site");

// ---- MATCHA SPLASH BACKGROUND (canvas-driven) ----
(function () {
  const canvas = document.getElementById('matchaCanvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const DPR = Math.min(window.devicePixelRatio || 1, 2);

  function resize() {
    const rect = canvas.parentElement.getBoundingClientRect();
    canvas.width = rect.width * DPR;
    canvas.height = rect.height * DPR;
    ctx.setTransform(DPR, 0, 0, DPR, 0, 0);
  }
  resize();
  window.addEventListener('resize', resize);

  // ---- kawaii ice cube image (base64-embedded, transparent background) ----
  const ICE_CUBE_IMG = new Image();
  let iceCubeImgReady = false;
  ICE_CUBE_IMG.onload = () => { iceCubeImgReady = true; };
  ICE_CUBE_IMG.src = 'data:image/png;base64,';
  const ICE_CUBE_ASPECT = 525 / 580; // native height / width

  const N = 48;
  const MATCHA_GREEN = '#2E6F3E';
  const FOAM = '#DCE9D6';

  function easeOutQuint(t) { return 1 - Math.pow(1 - t, 5); }
  function easeInOutCubic(t) { return t < 0.5 ? 4*t*t*t : 1 - Math.pow(-2*t+2,3)/2; }

  function waveParamsAt(t, H) {
    let baseLeft, baseRight, amp, phase;
    if (t < 0.42) {
      const p = easeOutQuint(t / 0.42);
      baseLeft = H * 1.0 - p * (H * 1.0 - H * 0.08);
      baseRight = H * 0.994 - p * (H * 0.994 - H * 0.05);
      amp = 6 + p * (H * 0.05);
      phase = p * 2.1;
    } else {
      const p = easeInOutCubic((t - 0.42) / 0.58);
      const overshootLeft = H * 0.08, overshootRight = H * 0.05;
      const finalLeft = H * 0.15, finalRight = H * 0.155;
      const bounce = Math.sin(p * Math.PI) * (H * 0.025) * (1 - p);
      baseLeft = overshootLeft + p * (finalLeft - overshootLeft) - bounce;
      baseRight = overshootRight + p * (finalRight - overshootRight) - bounce;
      amp = H * 0.05 - p * (H * 0.035);
      phase = 2.1 + p * 1.3;
    }
    return { baseLeft, baseRight, amp, phase };
  }

  // idle state: small continuous shimmer once settled
  function idleParams(H, t) {
    const baseLeft = H * 0.15, baseRight = H * 0.155;
    const amp = H * 0.018 + Math.sin(t * 0.0006) * H * 0.006;
    const phase = t * 0.0014;
    return { baseLeft, baseRight, amp, phase };
  }

  let lastWavePath = null;

  // ---- ice cubes: glassy, drift/bob inside the matcha body ----
  const ICE_CUBES = [
    { fx: 0.08, fyBase: 0.30, size: 1.3, bobSpeed: 0.00085, bobAmp: 0.018, driftSpeed: 0.00021, driftAmp: 0.05,  rot: -8,  phase0: 0.2 },
    { fx: 0.22, fyBase: 0.55, size: 2.3, bobSpeed: 0.00079, bobAmp: 0.016, driftSpeed: 0.00023, driftAmp: 0.045, rot: -10, phase0: 1.1 },
    { fx: 0.34, fyBase: 0.32, size: 0.9, bobSpeed: 0.00098, bobAmp: 0.022, driftSpeed: 0.00026, driftAmp: 0.05,  rot: 14,  phase0: 1.8 },
    { fx: 0.46, fyBase: 0.78, size: 1.7, bobSpeed: 0.00071, bobAmp: 0.014, driftSpeed: 0.00022, driftAmp: 0.04,  rot: 9,   phase0: 2.4 },
    { fx: 0.58, fyBase: 0.40, size: 1.1, bobSpeed: 0.00105, bobAmp: 0.026, driftSpeed: 0.00019, driftAmp: 0.045, rot: -16, phase0: 3.1 },
    { fx: 0.68, fyBase: 0.65, size: 2.0, bobSpeed: 0.00082, bobAmp: 0.015, driftSpeed: 0.00024, driftAmp: 0.038, rot: -6,  phase0: 3.7 },
    { fx: 0.78, fyBase: 0.28, size: 1.4, bobSpeed: 0.00091, bobAmp: 0.02,  driftSpeed: 0.0002,  driftAmp: 0.042, rot: 12,  phase0: 4.4 },
    { fx: 0.88, fyBase: 0.50, size: 0.95,bobSpeed: 0.00099, bobAmp: 0.013, driftSpeed: 0.00028, driftAmp: 0.03,  rot: -20, phase0: 0.9 },
    { fx: 0.97, fyBase: 0.36, size: 1.8, bobSpeed: 0.00076, bobAmp: 0.017, driftSpeed: 0.00024, driftAmp: 0.04,  rot: 18,  phase0: 5.6 },
    { fx: 0.14, fyBase: 0.88, size: 1.6, bobSpeed: 0.00068, bobAmp: 0.015, driftSpeed: 0.00027, driftAmp: 0.038, rot: 4,   phase0: 2.5 },
    { fx: 0.52, fyBase: 0.92, size: 2.4, bobSpeed: 0.00073, bobAmp: 0.014, driftSpeed: 0.00021, driftAmp: 0.035, rot: -12, phase0: 5.0 },
    { fx: 0.84, fyBase: 0.72, size: 1.2, bobSpeed: 0.00088, bobAmp: 0.019, driftSpeed: 0.00025, driftAmp: 0.04,  rot: 8,   phase0: 0.5 }
  ];

  // draws the real kawaii ice cube artwork (image), keeping the same
  // soft submerged shadow + rotation/sizing behavior as before
  function drawIceCube(cx, cy, size, rotDeg) {
    if (!iceCubeImgReady) return; // skip silently until the image has loaded

    const w = 22 * size;
    const h = w * ICE_CUBE_ASPECT;

    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate((rotDeg * Math.PI) / 180);

    // soft shadow smudge beneath the cube (reads through liquid)
    ctx.save();
    ctx.globalAlpha = 0.16;
    ctx.fillStyle = '#1B3F24';
    ctx.beginPath();
    ctx.ellipse(0, h * 0.52, w * 0.5, h * 0.18, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.drawImage(ICE_CUBE_IMG, -w / 2, -h / 2, w, h);

    ctx.restore();
  }

  function drawIceCubes(wavePath, t) {
    if (!wavePath) return;
    const { points, W, H } = wavePath;

    ctx.save();
    // clip to the matcha wave shape so cubes look submerged, not floating above it
    ctx.beginPath();
    ctx.moveTo(points[0][0], points[0][1]);
    for (let i = 1; i < points.length; i++) ctx.lineTo(points[i][0], points[i][1]);
    ctx.lineTo(W, H);
    ctx.lineTo(0, H);
    ctx.closePath();
    ctx.clip();

    ICE_CUBES.forEach(cube => {
      const bob = Math.sin(t * cube.bobSpeed + cube.phase0) * H * cube.bobAmp;
      const drift = Math.sin(t * cube.driftSpeed + cube.phase0 * 1.4) * W * cube.driftAmp;
      const wobbleRot = cube.rot + Math.sin(t * cube.bobSpeed * 0.6 + cube.phase0) * 4;

      const cx = cube.fx * W + drift;
      const cy = cube.fyBase * H + bob;
      const size = (Math.min(W, H) / 170) * cube.size;

      drawIceCube(cx, cy, Math.max(size, 0.55), wobbleRot);
    });

    ctx.restore();
  }

  function drawWave(baseLeft, baseRight, amp, phase, W, H) {
    ctx.clearRect(0, 0, W, H);

    // main matcha body
    ctx.beginPath();
    ctx.moveTo(0, H);
    const points = [];
    for (let i = 0; i <= N; i++) {
      const tt = i / N;
      const x = tt * W;
      const base = baseLeft + (baseRight - baseLeft) * tt;
      const y = base + amp * Math.sin(phase + tt * 1.5 * 2 * Math.PI);
      points.push([x, y]);
    }
    ctx.lineTo(points[0][0], points[0][1]);
    for (let i = 1; i < points.length; i++) ctx.lineTo(points[i][0], points[i][1]);
    ctx.lineTo(W, H);
    ctx.closePath();
    const grad = ctx.createLinearGradient(0, Math.min(baseLeft, baseRight) - amp, 0, H);
    grad.addColorStop(0, '#4FA160');
    grad.addColorStop(1, '#2E6F3E');
    ctx.fillStyle = grad;
    ctx.fill();
    lastWavePath = { points: points.slice(), W, H };

    // foam line tracing the surface, slightly above it
    ctx.beginPath();
    ctx.moveTo(points[0][0], points[0][1] - 4);
    for (let i = 1; i < points.length; i++) ctx.lineTo(points[i][0], points[i][1] - 4);
    ctx.strokeStyle = 'rgba(220,233,214,0.55)';
    ctx.lineWidth = 3;
    ctx.stroke();

    // tiny foam bubbles riding the line
    for (let i = 0; i < 9; i++) {
      const tt = (i / 8 + phase * 0.02) % 1;
      const x = tt * W;
      const base = baseLeft + (baseRight - baseLeft) * tt;
      const y = base + amp * Math.sin(phase + tt * 1.5 * 2 * Math.PI) - 5;
      ctx.beginPath();
      ctx.arc(x, y, 1.6 + (i % 3), 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(220,233,214,0.4)';
      ctx.fill();
    }
  }


  const SPLASH_DURATION = 1250;
  const STRAW_START = 1100;
  let startTime = null;
  let baseTopRef = 0;

  function frame(now) {
    if (startTime === null) startTime = now;
    const elapsed = now - startTime;
    const W = canvas.width / DPR, H = canvas.height / DPR;

    if (elapsed < SPLASH_DURATION) {
      const t = elapsed / SPLASH_DURATION;
      const { baseLeft, baseRight, amp, phase } = waveParamsAt(t, H);
      baseTopRef = Math.min(baseLeft, baseRight);
      drawWave(baseLeft, baseRight, amp, phase, W, H);
    } else {
      const idleT = elapsed - SPLASH_DURATION;
      const { baseLeft, baseRight, amp, phase } = idleParams(H, idleT);
      baseTopRef = Math.min(baseLeft, baseRight);
      drawWave(baseLeft, baseRight, amp, phase, W, H);
      drawIceCubes(lastWavePath, idleT);
    }
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

  // stop animating once the gate is unlocked, to save cycles
  gateForm.addEventListener(
    "submit",
    () => {
      stopped = true;
      if (rafId) cancelAnimationFrame(rafId);
    },
    { once: true }
  );
})();

function unlockSite() {
  gate.classList.add("closing");
  setTimeout(() => {
    gate.style.display = "none";
    site.hidden = false;
    window.scrollTo({ top: 0 });
  }, 480);
}

// Optional: remember the unlock for this browser so guests don't
// have to re-enter the password every visit.
try {
  if (sessionStorage.getItem("irisMatchaUnlocked") === "true") {
    gate.style.display = "none";
    site.hidden = false;
  }
} catch (e) {
  /* sessionStorage unavailable — gate just shows every time, no big deal */
}

gateForm.addEventListener("submit", function (e) {
  e.preventDefault();
  const entered = passwordInput.value.trim().toLowerCase();

  if (entered === SITE_PASSWORD.toLowerCase()) {
    gateError.classList.remove("show");
    try { sessionStorage.setItem("irisMatchaUnlocked", "true"); } catch (e) {}
    unlockSite();
  } else {
    gateError.classList.add("show");
    gateCard.classList.remove("shake");
    // restart animation
    requestAnimationFrame(() => {
      gateCard.classList.add("shake");
    });
    passwordInput.select();
  }
});

gateCard.addEventListener("animationend", (e) => {
  if (e.animationName === "shake") {
    gateCard.classList.remove("shake");
  }
});

// ---- RSVP FORM ----
const rsvpForm = document.getElementById("rsvpForm");
const rsvpSuccess = document.getElementById("rsvpSuccess");

if (rsvpForm) {
  rsvpForm.addEventListener("submit", async function (e) {
    e.preventDefault();
    const submitBtn = rsvpForm.querySelector(".rsvp-button");
    const originalText = submitBtn.textContent;
    submitBtn.textContent = "Sending...";
    submitBtn.disabled = true;

    try {
      const formData = new FormData(rsvpForm);
      const response = await fetch(rsvpForm.action, {
        method: "POST",
        body: formData,
        headers: { Accept: "application/json" },
      });

      if (response.ok) {
        rsvpForm.reset();
        rsvpSuccess.classList.add("show");
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
      } else {
        throw new Error("Form submission failed");
      }
    } catch (err) {
      submitBtn.textContent = "Try again";
      submitBtn.disabled = false;
      alert("Something went wrong sending your RSVP — mind trying again, or just texting Iris directly?");
    }
  });
}
